from typing import List

class Solution:
    def possibleBipartition(self, n: int, dislikes: List[List[int]]) -> bool:
        graph = [[] for _ in range(n + 1)]
        for a, b in dislikes:
            graph[a].append(b)
            graph[b].append(a)

        color = [0] * (n + 1)

        def dfs(node: int, col: int) -> bool:
            color[node] = col
            for neighbor in graph[node]:
                if color[neighbor] == col:
                    return False
                if color[neighbor] == 0 and not dfs(neighbor, 3 - col):
                    return False
            return True

        for i in range(1, n + 1):
            if color[i] == 0 and not dfs(i, 1):
                return False
        return True
```

